import math
import numpy as np

def overlapping_max_pool2d(x: np.ndarray, kernel_size: int = 3, stride: int = 2) -> np.ndarray:
    """
    Applies overlapping max pooling to a 4D tensor (N, C, H, W).
    Uses ceil mode for output dimensions (allows partial windows at boundaries).
    """
    N, C, H, W = x.shape

    # Ceil mode: out = ceil((in - kernel_size) / stride) + 1
    out_H = math.ceil((H - kernel_size) / stride) + 1
    out_W = math.ceil((W - kernel_size) / stride) + 1

    output = [[[[0.0] * out_W for _ in range(out_H)] for _ in range(C)] for _ in range(N)]

    for n in range(N):
        for c in range(C):
            for oh in range(out_H):
                for ow in range(out_W):
                    h_start = oh * stride
                    w_start = ow * stride
                    h_end = min(h_start + kernel_size, H)  # clamp to valid input
                    w_end = min(w_start + kernel_size, W)

                    max_val = float('-inf')
                    for h in range(h_start, h_end):
                        for w in range(w_start, w_end):
                            if x[n, c, h, w] > max_val:
                                max_val = x[n, c, h, w]

                    output[n][c][oh][ow] = max_val

    return np.array(output)
